defmodule MyApp.Accounts.User do
  use Ecto.Schema
  import Ecto.Changeset

  @allowed_fields [:name, :email, :role, :tenant_id, :phone, :avatar_url, :status]
  @required_fields [:name, :email, :role, :tenant_id]

  # Fields that each role is allowed to update
  @role_field_permissions %{
    "super_admin" => [:name, :email, :role, :tenant_id, :phone, :avatar_url, :status],
    "admin" => [:name, :email, :phone, :avatar_url, :status],
    "manager" => [:name, :phone, :avatar_url],
    "user" => [:name, :phone, :avatar_url]
  }

  schema "users" do
    field :name, :string
    field :email, :string
    field :role, :string
    field :tenant_id, :integer
    field :phone, :string
    field :avatar_url, :string
    field :status, :string, default: "active"

    timestamps()
  end

  def changeset(user, params) do
    user
    |> cast(params, @allowed_fields)
    |> validate_required(@required_fields)
    |> validate_format(:email, ~r/^[^\s]+@[^\s]+\.[^\s]+$/)
    |> validate_inclusion(:role, ["super_admin", "admin", "manager", "user"])
    |> validate_inclusion(:status, ["active", "inactive", "suspended"])
    |> unique_constraint(:email)
  end

  @doc """
  Creates a changeset that only allows fields the given role is permitted to update.
  Strips any unauthorized fields from params before casting.
  """
  def authorized_changeset(user, params, actor_role) do
    permitted_fields = Map.get(@role_field_permissions, actor_role, [])

    sanitized_params =
      params
      |> Enum.filter(fn {key, _value} ->
        atom_key = if is_binary(key), do: String.to_existing_atom(key), else: key
        atom_key in permitted_fields
      end)
      |> Map.new()

    user
    |> cast(sanitized_params, permitted_fields)
    |> validate_required(@required_fields)
    |> validate_format(:email, ~r/^[^\s]+@[^\s]+\.[^\s]+$/)
    |> validate_inclusion(:role, ["super_admin", "admin", "manager", "user"])
    |> validate_inclusion(:status, ["active", "inactive", "suspended"])
    |> unique_constraint(:email)
  end

  def allowed_fields_for_role(role) do
    Map.get(@role_field_permissions, role, [])
  end
end

defmodule MyApp.Accounts.Authorization do
  @moduledoc """
  Server-side authorization module that enforces resource, tenant, role,
  and field-level access control.
  """

  alias MyApp.Accounts.User

  @doc """
  Checks whether the actor is authorized to update the target user.
  Returns :ok or {:error, reason}.
  """
  def authorize_update(actor, target_user, params) do
    with :ok <- check_tenant_access(actor, target_user),
         :ok <- check_role_hierarchy(actor, target_user),
         :ok <- check_self_update_restrictions(actor, target_user, params),
         :ok <- check_field_permissions(actor, params) do
      :ok
    end
  end

  @doc """
  Ensures the actor belongs to the same tenant as the target user,
  unless the actor is a super_admin.
  """
  def check_tenant_access(%User{role: "super_admin"}, _target_user), do: :ok

  def check_tenant_access(%User{tenant_id: actor_tenant}, %User{tenant_id: target_tenant})
      when actor_tenant == target_tenant,
      do: :ok

  def check_tenant_access(_actor, _target_user),
    do: {:error, :forbidden, "Cannot modify users in a different tenant"}

  @doc """
  Ensures the actor has sufficient role privileges to update the target user.
  """
  def check_role_hierarchy(actor, target_user) do
    actor_level = role_level(actor.role)
    target_level = role_level(target_user.role)

    cond do
      actor.id == target_user.id ->
        :ok

      actor_level > target_level ->
        :ok

      true ->
        {:error, :forbidden, "Insufficient role privileges to update this user"}
    end
  end

  @doc """
  Prevents users from escalating their own role or changing their own tenant.
  """
  def check_self_update_restrictions(%User{id: id}, %User{id: id}, params) do
    param_keys =
      params
      |> Map.keys()
      |> Enum.map(fn key -> if is_binary(key), do: String.to_existing_atom(key), else: key end)

    restricted_self_fields = [:role, :tenant_id, :status]

    has_restricted =
      Enum.any?(param_keys, fn key -> key in restricted_self_fields end)

    if has_restricted do
      {:error, :forbidden, "Cannot modify your own role, tenant, or status"}
    else
      :ok
    end
  end

  def check_self_update_restrictions(_actor, _target, _params), do: :ok

  @doc """
  Ensures the actor's role permits updating all the fields present in params.
  """
  def check_field_permissions(actor, params) do
    allowed = User.allowed_fields_for_role(actor.role)

    unauthorized_fields =
      params
      |> Map.keys()
      |> Enum.map(fn key -> if is_binary(key), do: String.to_existing_atom(key), else: key end)
      |> Enum.reject(fn key -> key in allowed end)

    if unauthorized_fields == [] do
      :ok
    else
      field_names = Enum.map(unauthorized_fields, &to_string/1) |> Enum.join(", ")
      {:error, :forbidden, "Not authorized to update fields: #{field_names}"}
    end
  end

  defp role_level("super_admin"), do: 4
  defp role_level("admin"), do: 3
  defp role_level("manager"), do: 2
  defp role_level("user"), do: 1
  defp role_level(_), do: 0
end

defmodule MyApp.Accounts do
  @moduledoc """
  Context module for user account operations.
  """

  alias MyApp.Repo
  alias MyApp.Accounts.{User, Authorization}

  def get_user!(id), do: Repo.get!(User, id)

  def get_user(id), do: Repo.get(User, id)

  @doc """
  Updates a user with full authorization checks.
  The actor is the currently authenticated user performing the update.
  """
  def update_user(actor, target_user, params) do
    with :ok <- Authorization.authorize_update(actor, target_user, params) do
      target_user
      |> User.authorized_changeset(params, actor.role)
      |> Repo.update()
    end
  end

  @doc """
  Lists users scoped to the actor's tenant (super_admins see all).
  """
  def list_users_for_actor(%User{role: "super_admin"}) do
    Repo.all(User)
  end

  def list_users_for_actor(%User{tenant_id: tenant_id}) do
    import Ecto.Query
    Repo.all(from u in User, where: u.tenant_id == ^tenant_id)
  end
end

defmodule MyAppWeb.UserController do
  use MyAppWeb, :controller

  alias MyApp.Accounts
  alias MyApp.Accounts.Authorization

  action_fallback MyAppWeb.FallbackController

  plug :load_current_user

  @doc """
  GET /api/users/:id
  """
  def show(conn, %{"id" => id}) do
    actor = conn.assigns.current_user
    target_user = Accounts.get_user!(id)

    with :ok <- Authorization.check_tenant_access(actor, target_user) do
      conn
      |> put_status(:ok)
      |> render("show.json", user: target_user)
    end
  end

  @doc """
  GET /api/users
  """
  def index(conn, _params) do
    actor = conn.assigns.current_user
    users = Accounts.list_users_for_actor(actor)

    conn
    |> put_status(:ok)
    |> render("index.json", users: users)
  end

  @doc """
  PUT/PATCH /api/users/:id

  Accepts user params and performs server-side authorization checks for:
  - Resource existence
  - Tenant isolation
  - Role hierarchy
  - Field-level permissions
  - Self-update restrictions
  """
  def update(conn, %{"id" => id} = params) do
    actor = conn.assigns.current_user
    user_params = Map.get(params, "user", params) |> Map.drop(["id"])

    target_user = Accounts.get_user!(id)

    case Accounts.update_user(actor, target_user, user_params) do
      {:ok, updated_user} ->
        conn
        |> put_status(:ok)
        |> render("show.json", user: updated_user)

      {:error, :forbidden, message} ->
        conn
        |> put_status(:forbidden)
        |> json(%{error: %{status: 403, message: message}})

      {:error, %Ecto.Changeset{} = changeset} ->
        conn
        |> put_status(:unprocessable_entity)
        |> put_view(MyAppWeb.ChangesetView)
        |> render("error.json", changeset: changeset)
    end
  end

  defp load_current_user(conn, _opts) do
    case conn.assigns[:current_user] do
      nil ->
        conn
        |> put_status(:unauthorized)
        |> json(%{error: %{status: 401, message: "Authentication required"}})
        |> halt()

      _user ->
        conn
    end
  end
end

defmodule MyAppWeb.FallbackController do
  use MyAppWeb, :controller

  def call(conn, {:error, :forbidden, message}) do
    conn
    |> put_status(:forbidden)
    |> json(%{error: %{status: 403, message: message}})
  end

  def call(conn, {:error, :not_found}) do
    conn
    |> put_status(:not_found)
    |> json(%{error: %{status: 404, message: "Resource not found"}})
  end

  def call(conn, {:error, %Ecto.Changeset{} = changeset}) do
    conn
    |> put_status(:unprocessable_entity)
    |> put_view(MyAppWeb.ChangesetView)
    |> render("error.json", changeset: changeset)
  end
end

defmodule MyAppWeb.UserView do
  use MyAppWeb, :view

  def render("index.json", %{users: users}) do
    %{data: Enum.map(users, &user_json/1)}
  end

  def render("show.json", %{user: user}) do
    %{data: user_json(user)}
  end

  defp user_json(user) do
    %{
      id: user.id,
      name: user.name,
      email: user.email,
      role: user.role,
      tenant_id: user.tenant_id,
      phone: user.phone,
      avatar_url: user.avatar_url,
      status: user.status,
      inserted_at: user.inserted_at,
      updated_at: user.updated_at
    }
  end
end

defmodule MyAppWeb.ChangesetView do
  use MyAppWeb, :view

  def render("error.json", %{changeset: changeset}) do
    errors =
      Ecto.Changeset.traverse_errors(changeset, fn {msg, opts} ->
        Regex.replace(~r"%{(\w+)}", msg, fn _, key ->
          opts |> Keyword.get(String.to_existing_atom(key), key) |> to_string()
        end)
      end)

    %{error: %{status: 422, message: "Validation failed", details: errors}}
  end
end